class Solution:
    def minLength(self, nums, k):
        # Brute force: for every left endpoint, grow the right endpoint while
        # tracking the exact set of distinct values seen so far, stopping at
        # the first window that reaches k (further growth only lengthens it).
        n = len(nums)
        best = -1
        for left in range(n):
            seen = set()
            total = 0
            for right in range(left, n):
                v = nums[right]
                if v not in seen:
                    seen.add(v)
                    total += v
                if total >= k:
                    length = right - left + 1
                    if best == -1 or length < best:
                        best = length
                    break
        return best

