class Solution:
    def minLength(self, nums, k):
        from collections import defaultdict
        count = defaultdict(int)
        distinct_sum = 0
        best = -1
        left = 0
        n = len(nums)
        for right in range(n):
            v = nums[right]
            if count[v] == 0:
                distinct_sum += v
            count[v] += 1
            while distinct_sum >= k:
                length = right - left + 1
                if best == -1 or length < best:
                    best = length
                lv = nums[left]
                count[lv] -= 1
                if count[lv] == 0:
                    distinct_sum -= lv
                left += 1
        return best

