var minLength = function(nums, k) {
    const count = new Map();
    let distinctSum = 0;
    let best = -1;
    let left = 0;
    const n = nums.length;
    for (let right = 0; right < n; right++) {
        const v = nums[right];
        const c = count.get(v) || 0;
        if (c === 0) distinctSum += v;
        count.set(v, c + 1);
        while (distinctSum >= k) {
            const length = right - left + 1;
            if (best === -1 || length < best) best = length;
            const lv = nums[left];
            const lc = count.get(lv) - 1;
            count.set(lv, lc);
            if (lc === 0) distinctSum -= lv;
            left++;
        }
    }
    return best;
};
